#include "light_sensor.h"
#include <Arduino.h>
#define LDR_PIN 34
static int _raw=0;static float _pct=0;static bool _dark=false;static unsigned long _l=0;
void ldr_setup(){pinMode(LDR_PIN,INPUT);Serial.println("[ldr] OK");}
void ldr_loop(){if(millis()-_l<500)return;_l=millis();_raw=analogRead(LDR_PIN);_pct=_raw*100.0/4095.0;_dark=_raw<500;}
int ldr_get_raw(){return _raw;}
float ldr_get_percent(){return _pct;}
bool ldr_is_dark(){return _dark;}
